import psutil
# @app.task(rate_limit='3/m')
def convert_to(folder, source):
    from .utils import randomString2
    randomname = randomString2(5)
    print('-------------------------------------------coversion start')
    args = [libreoffice_exec(),f'\"-env:UserInstallation=file:///tmp/LibreOffice_Conversion_{randomString2(5)}\"', '--headless', '--convert-to', 'pdf', '--outdir', folder, source]
    # print('-------------------------------------------coversion start tryyy')
    process=''
    quality=75
    try:
        # print('----------------------doneeeee covertttttttttttttttttttttttttttt')

        try:
            process = subprocess.Popen(args, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
            # process =subprocess.Popen([
            # 'soffice', '--headless', '--convert-to', 'pdf','--outdir',folder, source

            # ],stdout=subprocess.PIPE, stderr=subprocess.PIPE)
            process.communicate(timeout=100)
            # stdout, stderr = process.communicate(timeout=100)
            # Check for errors in the stderr output
            # if stderr:
            #     print(f"Error during conversion: {stderr.decode()}")
            # else:
            #     print(f"Conversion successful for {source}")
            return True
        #     # Wait for the process to complete or timeout
        #     process.wait(timeout=200)
        #     return True
        except Exception as e:
            threshold=90
            # print('----------------------------------process.pid',process.pid)
            for proc in psutil.process_iter(['pid', 'name', 'cpu_percent']):
                if proc.info['name'] == 'soffice.bin':
                    cpu_usage = proc.cpu_percent(interval=1)
                    print(f"soffice.bin CPU usage: {cpu_usage}%")
                    
                    if cpu_usage > threshold:
                        print('----------------------------------process.pid222222',proc.info['pid'])
                        os.kill(proc.info['pid'], 9)

            print("Subprocess timed out, terminating...",e)
            import time
            time.sleep(4)
            # process.terminate()
            # process.kill()
            return False
        # # filename = re.search('-> (.*?) using filter', process.stdout.decode())
        # # tt=1
        # # if filename:
        # #     return filename.group(1)
        # # else:
        # #     return tt

    except Exception as e:
        print('-------------------------------------------------------------------------------more than 5 secccccccccccccc',e)
        return False


def libreoffice_exec():
    # TODO: Provide support for more platforms
    if sys.platform == 'darwin':
        return '/usr/bin/soffice'
    return 'libreoffice'


def randomString2(stringLength=8):
    """Generate a random string of fixed length """
    letters= string.ascii_lowercase
    return ''.join(random.sample(letters,stringLength))

def convert_to1(folder, source):
    from .utils import randomString2
    randomname = randomString2(5)
    args = [libreoffice_exec1(),f'\"-env:UserInstallation=file:///tmp/LibreOffice_Conversion_{randomString2(5)}\"', '--headless', '--convert-to', 'pdf', '--outdir', folder, source]
    process = subprocess.run(args, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    filename = re.search('-> (.*?) using filter', process.stdout.decode())
    tt=1
    if filename:
        return filename.group(1)
    else:
        return tt

def libreoffice_exec1():
    # TODO: Provide support for more platforms
    if sys.platform == 'darwin':
        return '/usr/bin/soffice'
    return 'libreoffice'



