class get_single_redacted_pdf(APIView):
    authentication_classes = (TokenAuthentication, )
    permission_classes = (IsAuthenticated, )


    def get(self, request, pk, format=None):

        # folder=DataroomFolder.objects.get(id=pk)
        red=Redacted_Pdf.objects.filter(id=pk,is_deleted=False,is_deleted_permanent=False)
        redact=red.values('id','folder_id','name','user__first_name','user__last_name','dataroom_id','created_date','current_version','version','file','notes')
        RedactorVersion.objects.create(folder_id=red.last().folder.id,redact_id=red.last().id,user=request.user,event='redact view',dataroom_id=red.last().folder.dataroom.id)
        return Response(data=redact)



    def post(self, request, pk, format=None):

        # folder=DataroomFolder.objects.get(id=pk)
        redact=Redacted_Pdf.objects.filter(id=pk,is_deleted=False,is_deleted_permanent=False).last()
        Redacted_Pdf.objects.filter(folder_id=redact.folder.id).update(current_version=False)
        Redacted_Pdf.objects.filter(id=pk).update(current_version=True)
        RedactorVersion.objects.create(folder_id=redact.folder.id,redact_id=redact.id,user=request.user,event='redact set current version',dataroom_id=redact.folder.dataroom.id)
        return Response({'msg':'successfully Done'})





