class Redacte_Pdf(APIView):
    authentication_classes = (TokenAuthentication, )
    permission_classes = (IsAuthenticated, )


    def get(self, request, pk, format=None):

        folder=DataroomFolder.objects.get(id=pk,)
        url=folder.path.url
        pathsplit=url.split('/')
        fileext=pathsplit[-1].split('.')
        if fileext[-1]=='pdf':
            return Response(data=url)

        if fileext[-1]=='docx' or fileext[-1]=='doc' or fileext[-1]=='odt' or fileext[-1]=='xlsx' or fileext[-1]=='ppt' or fileext[-1]=='pptx' or fileext[-1]=='xls' or fileext[-1]=='csv' or fileext[-1]=='txt':
            # fileext[-1]='pdf'
            # fileext='.'.join(fileext)
 
            # blob_na=pathsplit[4]+"/"+fileext
            url_split=url.split('.')
            url_split[-1]='pdf'
            url_split='.'.join(url_split)
            return Response(data=url_split)

        else:
            data = {'unsupported file format'}
            return Response(data=data,status=status.HTTP_400_BAD_REQUEST)



