class FavouriteAllSelectedFiles(APIView):
    authentication_classes = (TokenAuthentication, )
    permission_classes = (IsAuthenticated, )


    def get(self, request, pk, format=None):
        user = request.user
        from data_documents import utils
        page = request.GET.get("page")
        # print('----------------',page)
        page1=str(page)+'0'
        # print('-----------------------',page1)
        page2=int(page)-1
        if page2 != 0:
            page2=str(page2)+'0'
        # print('-----------------------',page2)
        page1=int(page1)
        page2=int(page2)
        fav=Favourite.objects.filter(user=request.user,dataroom_id=pk,folder__is_deleted=False).order_by('-id').values('folder_id','folder__index','folder__file_size_mb','folder__name','folder__parent_folder','folder__is_folder','folder__updated_date','folder__file_size_mb')[page2:page1]
        for i in fav:
            # i['perm']=
            if user.is_superadmin == True or user.is_admin == True:
                i['perm']={}
                i['perm']['is_view_only'] = True
                i['perm']['is_no_access'] = False
                i['perm']['is_access'] = True
                i['perm']['is_view_and_print'] = True
                i['perm']['is_view_and_print_and_download'] = True
                i['perm']['is_upload'] = True
                i['perm']['is_watermarking'] = True
                i['perm']['is_drm'] = True
                i['perm']['is_editor'] = True
            else:
                perm = DataroomGroupFolderSpecificPermissions.objects.get(folder_id=i['folder_id'])
                perm_serializer = DataroomGroupFolderSpecificPermissionsSerializer(perm, many=False)
                i['perm'] = perm_serializer.data

            indexes = True
            if i['folder__is_folder'] == True:
                index = str(i['folder__index'])
            else:
                index = "0."+str(i['folder__index'])
            parent_folder = i['folder__parent_folder']
            while indexes == True:
                if parent_folder == None:
                    indexes = False
                else:
                    folder = DataroomFolder.objects.get(id=parent_folder)
                    index = str(folder.index)+'.'+str(index)
                    parent_folder = folder.parent_folder_id
            # print("Index------", index)
            i['index']=index   
        count=Favourite.objects.filter(user=request.user,dataroom_id=pk,folder__is_deleted=False).count()
        return Response({'data':fav,'count':count})



    def post(self, request, pk, format=None):
        data = request.data
        user = request.user
        
        # print("check the delete data value",data)
        folders = data.get('folder')
        print('---------favvvvvvvv-',folders)
        for _id in folders:
            # dataroom_folder = DataroomFolder.objects.get(id=_id)
            if Favourite.objects.filter(folder_id=_id,user=request.user,dataroom_id=pk).exists():
                pass
            else:
                Favourite.objects.create(folder_id=_id,user=request.user,dataroom_id=pk)




        return Response(data="successfully Done")


    def delete(self, request, pk, format=None):
        data = request.data
        user = request.user
        # print("check the delete data value",data)
        folders = data.get('folder')
        for _id in folders:
            # dataroom_folder = DataroomFolder.objects.get(id=_id)
            Favourite.objects.filter(folder_id=_id,user=request.user,dataroom_id=pk).delete()


        return Response(data="successfully Done")







