class GetAllNotViewedDocument(APIView):
    authentication_classes = (TokenAuthentication, )
    permission_classes = (IsAuthenticated, )

    def get(self, request, pk, format=None):
        # print ("get all recent document data")        
        user = request.user
        dataroompermission=dataroom_utils.checkdataroomaccess(user.id,int(pk))
        # print('TTTTTTTTTTTTTTTTTTTTTTTTTTTTTRRRRRRRRRRRRRRR',dataroompermission,user.id,pk)
        folderdata=[]
        if dataroompermission==False:
            data = request.data

            member = DataroomMembers.objects.filter(dataroom_id=pk,member_id=user.id,is_deleted=False).first()
            # perm_obj = DataroomGroupFolderSpecificPermissions.objects.filter(dataroom_id=pk, dataroom_groups_id=member.end_user_group.first().id).values('folder_id')
            permission_member_group = DataroomMembers.objects.filter(member_id=user.id,dataroom_id=pk).values('end_user_group')
            
            try:
                perm_obj = DataroomGroupFolderSpecificPermissions.objects.filter(dataroom_id=pk, dataroom_groups_id=member.end_user_group.first().id).values('folder_id')
                exclude_no_access_file = [i.folder_id for i in DataroomGroupFolderSpecificPermissions.objects.filter(dataroom_id=pk,dataroom_groups_id=member.end_user_group.first().id,is_view_only=False,is_no_access=True)]
            except:
                perm_obj = None
                exclude_no_access_file = []
            count = 0
            is_type =  int(request.GET.get('type'))
            view_list1 = FolderView.objects.filter(dataroom_id=pk, user_id=user.id,folder__is_deleted=False,folder__is_folder=False).order_by('-created_date').exclude(folder_id__in=exclude_no_access_file).values_list('folder_id',flat=True)
            
            # print(view_list1,'000000000000000000000llllllllllll')
            view_list1=list(dict.fromkeys(view_list1))
            # print(view_list1,'000000000000000000000llllllllllll')

            # print(view_list,'000000000000000000000llllllllllll')

            if is_type == 2:
                view_list = paginator.paginate_queryset(view_list1, request)

                if member.is_dataroom_admin or member.is_la_user:
                    count = DataroomFolder.objects.filter(id__in=view_list1, dataroom_id=pk,is_deleted=False, is_folder=False).count()
                    for i in view_list:
                        dataroom_folder = DataroomFolder.objects.filter(id=i, dataroom_id=pk,is_deleted=False, is_folder=False).last()
                        if dataroom_folder:
                            dataroom_folder = DataroomFolderSerializer(dataroom_folder, many=False).data

                            folderdata.append(dataroom_folder)
                else:
                    count = DataroomFolder.objects.filter(id__in=view_list1, dataroom_id=pk,is_deleted=False, is_folder=False).count()
                    for i in view_list:
                        dataroom_folder = DataroomFolder.objects.filter(id=i, dataroom_id=pk,is_deleted=False, is_folder=False).last()
                        if dataroom_folder:
                            dataroom_folder = DataroomFolderSerializer(dataroom_folder, many=False).data

                            folderdata.append(dataroom_folder)


            else:
                if member.is_dataroom_admin or member.is_la_user:
                    dataroom_folder = DataroomFolder.objects.exclude(id__in=view_list1).filter(dataroom_id=pk, is_deleted=False, is_folder=False).order_by('-created_date')
                    pagedata = paginator.paginate_queryset(dataroom_folder, request)
                    
                    folderdata = DataroomFolderSerializer(pagedata, many=True).data
                    # print(dataroom_folder,'iiiiiiiiiiiooooooooooo')
                    count = DataroomFolder.objects.exclude(id__in=view_list1).filter(dataroom_id=pk, is_deleted=False, is_folder=False).distinct('id').count()                
                else:
                    dataroom_folder = DataroomFolder.objects.exclude(id__in=view_list1).filter(id__in=perm_obj,dataroom_id=pk, is_deleted=False, is_folder=False).order_by('-created_date')
                    pagedata = paginator.paginate_queryset(dataroom_folder, request)
                    
                    folderdata = DataroomFolderSerializer(pagedata, many=True).data
                    
                    count = DataroomFolder.objects.exclude(id__in=view_list1).filter(id__in=perm_obj,dataroom_id=pk, is_deleted=False, is_folder=False).distinct('id').count()
                # folderdata = sorted(folderdata,key=lambda x : x['created_date'], reverse=True)


            # count = dataroom_folder
            # #print(count)

                
                # dataroom_folder = DataroomFolder.objects.exclude(id__in=view_list).filter(dataroom_id=pk, id__in=perm_obj,is_deleted=False, is_folder=False)
            from . import utils
            for da in folderdata:
                da['index'] = utils.getIndexes(da)
                da['parent_folders'] = DataroomFolder.objects.get(id = da['parent_folder']).name
                if member.is_end_user:
                    perm_obj = DataroomGroupFolderSpecificPermissions.objects.filter(dataroom_id=pk, dataroom_groups_id=member.end_user_group.first().id).first()
                    perm_serializer = DataroomGroupFolderSpecificPermissionsSerializer(perm_obj, many=False)
                    da['perm'] = perm_serializer.data
                else:
                    da['perm'] = {}
                    da['perm']['is_view_only'] = True
                    da['perm']['is_no_access'] = False
                    da['perm']['is_access'] = True
                    da['perm']['is_view_and_print'] = True
                    da['perm']['is_view_and_print_and_download'] = True
                    da['perm']['is_upload'] = True
                    da['perm']['is_watermarking'] = True
                    da['perm']['is_drm'] = True
                    da['perm']['is_editor'] = True
                    da['perm']['is_shortcut'] = True
            # print(count)
            return Response({'data':folderdata, 'size':count})
        else:
            return Response(None)

