    def assign_index(self, data , user, pk):
        index = 0
        try :
            # print ("data under assign_index is:", data)
            # print ("priamry key is", pk)
            max_index = DataroomFolder.objects.filter(parent_folder_id=pk, dataroom_id=data.get('dataroomId'), is_root_folder=False, is_folder=False, is_deleted=False,is_deleted_permanent=False).aggregate(Max('index'))
            # print ("max indx is", max_index)
            index = max_index.get('index__max')
            # print ("index is", index)
            if index is None:
                index = 0
        except :
            pass
        # print ("new index is", index+1)
        return index+1

    def assign_index_folder(self, data , user, pk):
        index = 0
        try :
            # print ("inside create new folder", data)
            max_index = DataroomFolder.objects.filter(dataroom_id=data.get('dataroomId'), parent_folder_id=pk, is_root_folder=False, is_folder=True, is_deleted=False,is_deleted_permanent=False).aggregate(Max('index'))
            index = max_index.get('index__max')
            # print ('max index now is', index)
            if index is None:
                index = 0
        except :
            pass
        # print ("index after +1 is", index+1)
        return index+1



