from django.db.models import F
class ExportOverviewReportold(APIView):
    """docstring for ActivitybyDateReport"""
    authentication_classes = (TokenAuthentication, )
    # permission_classes = (IsAuthenticated, )
    permission_classes = (AllowAny, )

    def post(self, request, pk, format=None):
        user = request.user
        import datetime
        data = []
        data111 = json.loads(request.data)
        # print(data,'this data we get ooooooooooooo')
        # ts = datetime.now().timestamp()
        # file_name = str(data['token'])+'_'+str(ts).split('.')[0]
        # print(request.data,'utururruuuuuuuuuuuuuuuuuuuuuu',data, "HHHHHHHHHH")
        objid=data111['statusid']
        # months_count=data111['mohthscount']
        # print(months_count,'lllllllllllllllllll------------------------------------------')
        # BulkDownloadstatus.objects.filter(id=objid).update(failfilecount=months_count)

        file_name_zip=str(BulkDownloadstatus.objects.filter(id=objid).last().filename.split('.')[0])
        # print(file_name)
        # BulkDownloadstatus.objects.filter(id=objid).update(failfilecount=int(pk))
        
        from_date = request.GET.get("from_date")
        to_date = request.GET.get("to_date")
        # print("from_date",from_date,to_date)
        todays_date = datetime.datetime.strftime(datetime.datetime.strptime( to_date, '%Y-%m-%d'),'%Y-%m-%d 23:59:59+05:30')
        first_date = datetime.datetime.strftime(datetime.datetime.strptime( from_date, '%Y-%m-%d'),'%Y-%m-%d 00:00:00+05:30')
        

        folder_view = FolderView.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date).annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
       
        data.extend(folder_view)


        folder_print = FolderPrint.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date).annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(folder_print)

        folder_download = FolderDownload.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date).annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(folder_download)

        workspace_view = DataroomView.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date).annotate(user_=F('user__first_name')).annotate(title=F('dataroom__dataroom_nameFront')).values('created_date','event','title','user_')
        data.extend(workspace_view)

        Folder_Drm_Download = FolderDrmDownload.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date).annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(Folder_Drm_Download)

        Folder_only_delete_record = FolderDeleteDownload.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date,folder_id__parent_folder_id__isnull=True).annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(Folder_only_delete_record)

        Folder_Copy = FolderOrFileCopy.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date, event='Copy Folder').annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(Folder_Copy)

        File_Copy = FolderOrFileCopy.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date, event='Copy File').annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(File_Copy)

        Folder_Move = FolderOrFileMove.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date, event='Move Folder').annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(Folder_Move)

        File_Move = FolderOrFileMove.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date, event='Move File').annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(File_Move)

        Bulk_Download_Files = BulkDownloadFiles.objects.filter(dataroom_id=pk,created_date__gte=first_date, created_date__lte=todays_date).exclude(folder=None).annotate(user_=F('user__first_name')).annotate(title=F('folder__name')).values('created_date','event','title','user_')
        data.extend(Bulk_Download_Files)

