        data.extend(folder_copy_data)

        folder_move_data = FolderOrFileMove.objects.filter(dataroom_id=pk, user_id=pk1).annotate(Event_By=F('user__first_name')).annotate(title=F('folder__name')).annotate(Date=F('created_date')).values('Date','event','title','Event_By')
