        data.extend(file_delete_data)

        folder_delete_data = FolderDeleteDownload.objects.filter(dataroom_id=pk, user_id=pk1,folder_id__parent_folder_id__isnull=True).annotate(Event_By=F('user__first_name')).annotate(title=F('folder__name')).annotate(Date=F('created_date')).values('Date','event','title','Event_By')
        data.extend(folder_delete_data)

