        # datas.extend(bulk_upload_data)
        document = Folderupload.objects.filter(dataroom_id=pk, user_id=pk1)
        
        data.extend(document.annotate(Event_By=F('user__first_name')).annotate(title=F('folder__name')).annotate(Date=F('created_date')).values('Date','event','title','Event_By'))
        

        bulk_upload_data = Folderuploadinbulk.objects.filter(dataroom_id=pk, user_id=user.id)
        # bulk_upload_data_serializer = FolderuploadinbulkSerializer(bulk_upload_data, many=True).data
