class DataroomMembersView(APIView):
    authentication_classes = (TokenAuthentication, )
    permission_classes = (IsAuthenticated, )

    def get(self, request, pk, format=None):
        user = request.user
        email = request.GET.get('key','')
        if Dataroom.objects.filter(id=pk,dataroom_version='Lite').exists():
            if dataroomProLiteFeatures.objects.filter(dataroom_id=pk,index_report_others=False).exists():
                members = DataroomMembers.objects.filter(dataroom_id=pk, is_deleted=False,member__email=request.user.email)
                serializer = DataroomMembersSerializer(members, many=True)
                return Response(serializer.data, status=status.HTTP_201_CREATED)          
        if email!='':
            email=email.lower()
            members = DataroomMembers.objects.filter(dataroom_id=pk, is_deleted=False,member__email__icontains=email)
        else:
            members = DataroomMembers.objects.filter(dataroom_id=pk, is_deleted=False)
        serializer = DataroomMembersSerializer(members, many=True)
        return Response(serializer.data, status=status.HTTP_201_CREATED)

