class FoldersHierarchypath(APIView):
    authentication_classes = (TokenAuthentication, )
    permission_classes = (IsAuthenticated, )

    def get(self, request, pk, format=None):
        user = request.user
        # print('this api  _____________1')
        folderid = request.GET.get('folder_id')
        folder_path_tree=[]
        tree_generation_flag=True
        # #print("Group Id", group_id)
        if folderid!='0':
            parent_id=folderid
            while tree_generation_flag==True:
                folder_data=DataroomFolder.objects.filter(dataroom_id = pk,id=parent_id, is_deleted=False,is_folder=True)
                if folder_data.exists():
                    folder_data=folder_data.last()
                    folder_path_tree.insert(0,DataroomFolderSerializer(folder_data,many=False).data)
                    if folder_data.parent_folder==None or folder_data.is_root_folder==True:
                        tree_generation_flag=False
                    else:
                        parent_id=folder_data.parent_folder.id
                else:
                    tree_generation_flag=False
        return Response(folder_path_tree, status=status.HTTP_201_CREATED)


