@csrf_exempt
def testing(request, pk):
    from typing import Tuple
    from io import BytesIO
    import os
    import argparse
    import re
    import fitz
    search_str='Lorem'
    os.chdir('/home/cdms_backend/cdms2/mediaa')
    input_file='A_Sample_PDF.pdf'
    pdfDoc = fitz.open(input_file)
    # Save the generated PDF to memory buffer
    output_buffer = BytesIO()
    total_matches = 0
    # Iterate through pages
    for pg in range(pdfDoc.pageCount):
        # If required for specific pages
        # if pages:
        #     if str(pg) not in pages:
        #         continue
        # Select the page
        page = pdfDoc[pg]
        # Get Matching Data

        # Split page by lines
        page_lines = page.getText("text").split('\n')
        matched_values = search_for_text(page_lines, search_str)
        if matched_values:
            # if action == 'Redact':
            matches_found = redact_matching_data(page, matched_values)
            total_matches += matches_found
    pdfDoc.save(output_buffer)
    pdfDoc.close()
    # Save the output buffer to the output file
    output_file='A_Sample_PDF23.pdf'
    with open(output_file, mode='wb') as f:
        f.write(output_buffer.getbuffer())

    return HttpResponse('------donee')






        


