    print('-------------------------file id',file_id)
    token = generate_wopi_token(file_id)
    print('-------------------------file idafter',file_id)
    wopi_src = f"https://stage.docullyvdr.com/wopi/files/{file_id}"

    # if file_type == "xlsx":
    base = "https://excel.officeapps.live.com/x/_layouts/Excel.aspx"
    # elif file_type == "docx":
    #     base = "https://word-edit.officeapps.live.com/we/wordeditorframe.aspx"
    # elif file_type == "pptx":
    #     base = "https://powerpoint.officeapps.live.com/p/PowerPoint.aspx"
    print(f"{base}?WOPISrc={wopi_src}?access_token={token}")

